import express from 'express';
import { Vex } from '@vex-sdk/nodejs';

const app = express();
app.use(express.raw({ type: 'application/json' }));

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

app.post('/openai-webhook', async (req, res) => {
  const event = JSON.parse(req.body);

  if (event.object === 'thread.run.created' && event.data.object === 'thread.run') {
    // Run completed - extract output
    const threadId = event.data.parent.thread_id;
    const messages = await openai.beta.threads.messages.list(threadId);
    const assistantMsg = messages.data.find(m => m.role === 'assistant');

    // Vex verification
    const result = await vex.verify({
      input: assistantMsg.content[0].text.value,
      checks: ['pii_filter', 'tone_professional', 'recipient_validation']
    });

    if (result.passed) {
      // Safe to send email
      console.log('Email verified, proceed to send');
    }
  }

  res.status(200).send('OK');
});

from flask import Flask, request

from vex import VexClient
vex = VexClient(api_key=os.getenv('VEX_API_KEY'))

app = Flask(__name__)

def verify_email_draft(content: str, recipients: list) -> bool:
    result = vex.verify(
        category='email_assistant',
        input=content,
        context={'recipients': recipients},
        checks=[
            'pii_filtering',
            'tone_appropriateness',
            'recipient_validation',
            'confidentiality_enforcement'
        ]
    )
    return result.passed

@app.route('/assistant-output', methods=['POST'])
def handle_assistant_output():
    data = request.json
    draft = data['draft_content']
    recipients = data['recipients']

    if verify_email_draft(draft, recipients):
        return {'status': 'approved', 'action': 'send_email'}
    else:
        return {'status': 'rejected', 'reason': 'vex_verification_failed'}

